function initPopulationJobsChart(){const canvasId="population-jobs-chart";const canvas=document.getElementById(canvasId);if(!canvas)return;const ctx=canvas.getContext("2d");const years=["2026","2027","2028","2029","2030","2035","2040"];const populationData=[12500,12850,13250,13700,14200,16100,17600];const jobsData=[4500,4800,5200,5700,6200,7500,8100];new Chart(ctx,{type:"line",data:{labels:years,datasets:[{label:"Population",data:populationData,borderColor:"#C8902A",backgroundColor:"rgba(200, 144, 42, 0.08)",borderWidth:3,fill:true,tension:.4,pointRadius:6,pointBackgroundColor:"#C8902A",pointBorderColor:"#fff",pointBorderWidth:3,pointHoverRadius:8,yAxisID:"y"},{label:"Net New Jobs Created",data:jobsData,borderColor:"#2E6E35",backgroundColor:"rgba(46, 110, 53, 0.08)",borderWidth:3,fill:true,tension:.4,pointRadius:6,pointBackgroundColor:"#2E6E35",pointBorderColor:"#fff",pointBorderWidth:3,pointHoverRadius:8,yAxisID:"y1"}]},options:{responsive:true,maintainAspectRatio:false,interaction:{mode:"index",intersect:false},plugins:{legend:{display:true,position:"top",labels:{usePointStyle:true,font:{size:12,weight:"600"},padding:15}},tooltip:{backgroundColor:"rgba(27, 58, 92, 0.9)",padding:12,titleFont:{size:13,weight:"bold"},bodyFont:{size:12},borderColor:"#C8902A",borderWidth:2}},scales:{y:{type:"linear",display:true,position:"left",title:{display:true,text:"Population",font:{weight:"bold"}},ticks:{color:"#1B3A5C"}},y1:{type:"linear",display:true,position:"right",title:{display:true,text:"Jobs",font:{weight:"bold"}},ticks:{color:"#2E6E35"},grid:{drawOnChartArea:false}},x:{ticks:{color:"#6B7280",font:{size:11}}}}}})}function initInvestmentPipelineChart(){const canvasId="investment-pipeline-chart";const canvas=document.getElementById(canvasId);if(!canvas)return;const ctx=canvas.getContext("2d");new Chart(ctx,{type:"doughnut",data:{labels:["Federal Grants\n($200M)","State Programs\n($100M)","Private Capital\n($600M)"],datasets:[{data:[200,100,600],backgroundColor:["#1B3A5C","#4A90BF","#C8902A"],borderColor:["#0D1B2A","#2E6E35","#A63D2F"],borderWidth:3,hoverBorderWidth:5}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:true,position:"bottom",labels:{font:{size:12,weight:"600"},padding:15,usePointStyle:true}},tooltip:{backgroundColor:"rgba(27, 58, 92, 0.9)",padding:12,callbacks:{label:function(context){const total=context.dataset.data.reduce((a,b)=>a+b,0);const percentage=(context.parsed/total*100).toFixed(1);return context.label.split("\n")[0]+": $"+context.parsed+"M ("+percentage+"%)"}}}}}})}function initCompetitiveRadarChart(){const canvasId="competitive-radar-chart";const canvas=document.getElementById(canvasId);if(!canvas)return;const ctx=canvas.getContext("2d");new Chart(ctx,{type:"radar",data:{labels:["Economic Metrics","Infrastructure","Workforce","Business Climate","Quality of Life","Housing Market","Unique Advantages"],datasets:[{label:"El Dorado",data:[7.5,8.8,6.5,7.8,7.2,6.8,9.2],borderColor:"#C8902A",backgroundColor:"rgba(200, 144, 42, 0.15)",borderWidth:3,pointRadius:5,pointBackgroundColor:"#C8902A"},{label:"Regional Average",data:[7.2,7.5,7,7.5,7.5,7.2,6.8],borderColor:"#4A90BF",backgroundColor:"rgba(74, 144, 191, 0.08)",borderWidth:2,pointRadius:4,pointBackgroundColor:"#4A90BF"}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:true,position:"bottom",labels:{font:{size:12,weight:"600"},padding:15}},tooltip:{backgroundColor:"rgba(27, 58, 92, 0.9)",padding:12,callbacks:{label:function(context){return context.dataset.label+": "+context.parsed.r.toFixed(1)+"/10"}}}},scales:{r:{min:0,max:10,ticks:{stepSize:2},grid:{color:"rgba(107, 114, 128, 0.2)"}}}}})}function initRiskHeatMap(){const container=document.getElementById("risk-heatmap-container");if(!container)return;const risks=[{id:1,name:"Data Center Director Hiring",probability:"HIGH (60%)",impact:"HIGH",description:"8-12 week delay if not hired by July 1",mitigation:"Executive recruiter, elevated salary to $135K"},{id:2,name:"Federal Grants Defunding",probability:"HIGH (60%)",impact:"HIGH",description:"$50M-$200M funding loss risk",mitigation:"Diversify sources (state, municipal bonds, EB-5)"},{id:3,name:"Brain Drain Continues",probability:"HIGH (60%)",impact:"HIGH",description:"Workforce unavailable despite facilities",mitigation:"Lifestyle positioning, startup ecosystem"},{id:6,name:"Data Center Market Softens",probability:"HIGH (50%)",impact:"HIGH",description:"12-24 month timeline extension risk",mitigation:"Diversify prospects, water differentiation"}];let html='<div class="risk-matrix-detail">';risks.forEach(risk=>{html+=`\n      <div class="risk-card critical">\n        <div class="risk-card-header">\n          <h4>${risk.name}</h4>\n          <span class="risk-badge critical">CRITICAL</span>\n        </div>\n        <div class="risk-card-metrics">\n          <div><strong>Probability:</strong> ${risk.probability}</div>\n          <div><strong>Impact:</strong> ${risk.impact}</div>\n        </div>\n        <div class="risk-card-description">${risk.description}</div>\n        <div class="risk-card-mitigation">\n          <strong>Mitigation:</strong> ${risk.mitigation}\n        </div>\n      </div>\n    `});html+="</div>";container.innerHTML=html;document.querySelectorAll(".risk-card").forEach(card=>{card.addEventListener("click",function(){this.classList.toggle("expanded")})})}function initReadinessGauge(){const container=document.getElementById("readiness-gauge-svg");if(!container)return;const readiness=8.6;const percentage=readiness/10*100;const rotation=percentage/100*180;const svg=`\n    <svg viewBox="0 0 200 120" style="width: 100%; height: 100%; max-width: 200px;">\n      \x3c!-- Background arc --\x3e\n      <path d="M 20 100 A 80 80 0 0 1 180 100" stroke="#e5e7eb" stroke-width="12" fill="none" stroke-linecap="round"/>\n\n      \x3c!-- Progress arc --\x3e\n      <path d="M 20 100 A 80 80 0 0 1 ${20+160*(percentage/100)} ${100-80*Math.sin(Math.PI*(percentage/100))}"\n            stroke="#C8902A" stroke-width="12" fill="none" stroke-linecap="round" style="transition: all 0.6s ease;"/>\n\n      \x3c!-- Labels --\x3e\n      <text x="10" y="115" font-size="8" fill="#999">0%</text>\n      <text x="185" y="115" font-size="8" fill="#999">100%</text>\n      <text x="100" y="50" font-size="28" font-weight="900" text-anchor="middle" fill="#1B3A5C" font-family="Inter">\n        ${readiness}\n      </text>\n      <text x="100" y="70" font-size="10" text-anchor="middle" fill="#6B7280">/10 Ready</text>\n    </svg>\n  `;container.innerHTML=svg}function initPartnerFilter(){const filterBtns=document.querySelectorAll("[data-filter]");const partnerCards=document.querySelectorAll(".partnership-card");filterBtns.forEach(btn=>{btn.addEventListener("click",function(){const filter=this.getAttribute("data-filter");filterBtns.forEach(b=>b.classList.remove("active"));this.classList.add("active");partnerCards.forEach(card=>{if(filter==="all"||card.getAttribute("data-sector")===filter){card.style.display="block";setTimeout(()=>card.classList.add("visible"),10)}else{card.style.display="none";card.classList.remove("visible")}})})})}function initFundingSearch(){const searchInput=document.getElementById("funding-search");const fundingCards=document.querySelectorAll(".funding-source-card");if(!searchInput)return;searchInput.addEventListener("input",function(){const query=this.value.toLowerCase();fundingCards.forEach(card=>{const text=card.textContent.toLowerCase();if(text.includes(query)){card.style.display="block";card.classList.add("visible")}else{card.style.display="none";card.classList.remove("visible")}})})}function initScenarioSelector(){const scenarioBtns=document.querySelectorAll("[data-scenario]");const scenarioContent=document.querySelectorAll("[data-scenario-content]");scenarioBtns.forEach(btn=>{btn.addEventListener("click",function(){const scenario=this.getAttribute("data-scenario");scenarioBtns.forEach(b=>b.classList.remove("active"));this.classList.add("active");scenarioContent.forEach(content=>{if(content.getAttribute("data-scenario-content")===scenario){content.style.display="block";setTimeout(()=>content.classList.add("visible"),10)}else{content.style.display="none";content.classList.remove("visible")}})})})}function initCollapsibles(){const headers=document.querySelectorAll(".collapsible-header");headers.forEach(header=>{header.addEventListener("click",function(){this.classList.toggle("active")})})}function initTimelineSync(){const timelineItems=document.querySelectorAll(".timeline-item");const observer=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add("visible")}})},{threshold:.3});timelineItems.forEach(item=>observer.observe(item))}function initAnimationTriggers(){const animatedElements=document.querySelectorAll("[data-animate]");const observer=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add("animated")}})},{threshold:.1});animatedElements.forEach(el=>observer.observe(el))}document.addEventListener("DOMContentLoaded",()=>{if(typeof Chart!=="undefined"){initPopulationJobsChart();initInvestmentPipelineChart();initCompetitiveRadarChart()}initRiskHeatMap();initReadinessGauge();initPartnerFilter();initFundingSearch();initScenarioSelector();initCollapsibles();initTimelineSync();initAnimationTriggers()});function trackEvent(category,action,label){if(typeof gtag!=="undefined"){gtag("event",action,{event_category:category,event_label:label})}}document.querySelectorAll(".btn--cta").forEach(btn=>{btn.addEventListener("click",function(){trackEvent("engagement","cta_click",this.textContent)})});document.querySelectorAll("[data-filter]").forEach(btn=>{btn.addEventListener("click",function(){trackEvent("engagement","filter_applied",this.getAttribute("data-filter"))})});document.querySelectorAll("[data-download]").forEach(link=>{link.addEventListener("click",function(){trackEvent("engagement","document_download",this.getAttribute("data-download"))})});document.querySelectorAll("[data-video]").forEach(video=>{if(video.tagName==="VIDEO"){video.addEventListener("play",function(){trackEvent("engagement","video_play",this.getAttribute("data-video"))})}});